#include <stdio.h>
#include <stdlib.h>
int main() {
    int N, M;
    scanf("%d", &N);
    scanf("%d", &M);
    if (M > N) {
        printf("Queue Overflow
");
        return 0;
    }
    int *rarity = (int *)malloc(M * sizeof(int));
    for (int i = 0; i < M; i++) {
        scanf("%d", &rarity[i]);
    }
    char order[5];
    scanf("%s", order);
    // Sorting
    for (int i = 0; i < M - 1; i++) {
        for (int j = i + 1; j < M; j++) {
            if ((order[0] == 'a' && rarity[i] > rarity[j]) || (order[0] == 'd' && rarity[i] < rarity[j])) {
                int temp = rarity[i];
                rarity[i] = rarity[j];
                rarity[j] = temp;
            }
        }
    }
    for (int i = 0; i < M; i++) {
        printf("%d", rarity[i]);
        if (i < M - 1) printf(" ");
    }
    printf("
");
    free(rarity);
    return 0;
}

