import java.util.*;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        int M = scanner.nextInt();
        if (M > N) {
            System.out.println("Queue Overflow");
            return;
        }
        int[] rarities = new int[M];
        for (int i = 0; i < M; i++) {
            rarities[i] = scanner.nextInt();
        }
        String order = scanner.next();
        Arrays.sort(rarities);
        if (order.equals("desc")) {
            for (int i = M - 1; i >= 0; i--) {
                System.out.print(rarities[i] + (i == 0 ? "" : " "));
            }
        } else {
            for (int i = 0; i < M; i++) {
                System.out.print(rarities[i] + (i == M - 1 ? "" : " "));
            }
        }
    }
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <limits.h>
int main() {
    int N, M;
    scanf("%d %d", &N, &M);
    int graph[N][N];
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            graph[i][j] = (i == j) ? 0 : INT_MAX;
        }
    }
    for (int i = 0; i < M; i++) {
        int u, v;
        scanf("%d %d", &u, &v);
        graph[u][v] = 1;
        graph[v][u] = 1;
    }
    int start;
    scanf("%d", &start);
    int distances[N];
    memset(distances, -1, sizeof(distances));
    distances[start] = 0;
    int queue[N], front = 0, rear = 0;
    queue[rear++] = start;
    while (front < rear) {
        int current = queue[front++];
        for (int i = 0; i < N; i++) {
            if (graph[current][i] == 1 && distances[i] == -1) {
                distances[i] = distances[current] + 1;
                queue[rear++] = i;
            }
        }
    }
    int output[N];
    int count = 0;
    for (int i = 0; i < N; i++) {
        if (i != start && distances[i] != -1) {
            output[count++] = distances[i];
        }
    }
    // Sort distances maintaining stability
    for (int i = 0; i < count - 1; i++) {
        for (int j = 0; j < count - 1 - i; j++) {
            if (output[j] > output[j + 1]) {
                int temp = output[j];
                output[j] = output[j + 1];
                output[j + 1] = temp;
            }
        }
    }
    for (int i = 0; i < count; i++) {
        printf("%d
", output[i]);
    }
    return 0;
}

