#include <stdio.h>
#include <stdlib.h>
int main() {
    int H, W;
    scanf("%d %d", &H, &W);
    int image[H][W];
    for (int i = 0; i < H; i++) {
        for (int j = 0; j < W; j++) {
            scanf("%d", &image[i][j]);
        }
    }
    int startY, startX, newColor;
    scanf("%d %d", &startY, &startX);
    scanf("%d", &newColor);
    int originalColor = image[startY][startX];
    int area = 0;
    // 塗りつぶし関数
    void floodFill(int y, int x) {
        if (y < 0 || y >= H || x < 0 || x >= W || image[y][x] != originalColor) return;
        image[y][x] = newColor;
        area++;
        floodFill(y + 1, x);
        floodFill(y - 1, x);
        floodFill(y, x + 1);
        floodFill(y, x - 1);
    }
    floodFill(startY, startX);
    // 画像出力
    for (int i = 0; i < H; i++) {
        for (int j = 0; j < W; j++) {
            printf("%d ", image[i][j]);
        }
        printf("
");
    }
    printf("%d
", area);
    return 0;
}

