import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int H = sc.nextInt();
        int W = sc.nextInt();
        int[][] image = new int[H][W];
        for (int i = 0; i < H; i++) {
            for (int j = 0; j < W; j++) {
                image[i][j] = sc.nextInt();
            }
        }
        int startY = sc.nextInt();
        int startX = sc.nextInt();
        int newColor = sc.nextInt();

        int originalColor = image[startY][startX];
        if (originalColor != newColor) {
            int area = fill(image, startY, startX, originalColor, newColor);
            printImage(image);
            System.out.println(area);
        } else {
            printImage(image);
            System.out.println(0);
        }
    }

    private static int fill(int[][] image, int y, int x, int originalColor, int newColor) {
        int H = image.length;
        int W = image[0].length;
        if (y < 0 || y >= H || x < 0 || x >= W || image[y][x] != originalColor) return 0;
        image[y][x] = newColor;
        int area = 1;
        area += fill(image, y + 1, x, originalColor, newColor);
        area += fill(image, y - 1, x, originalColor, newColor);
        area += fill(image, y, x + 1, originalColor, newColor);
        area += fill(image, y, x - 1, originalColor, newColor);
        return area;
    }

    private static void printImage(int[][] image) {
        for (int[] row : image) {
            for (int pixel : row) {
                System.out.print(pixel + " ");
            }
            System.out.println();
        }
    }
}

#include <stdio.h>
#include <stdlib.h>
int main() {
    int N;
    scanf("%d", &N);
    int scores[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &scores[i]);
    }
    int indices[N];
    for (int i = 0; i < N; i++) {
        indices[i] = i;
    }
    // バブルソートでスコアとインデックスをソート
    for (int i = 0; i < N - 1; i++) {
        for (int j = 0; j < N - 1 - i; j++) {
            if (scores[j] < scores[j + 1]) {
                int temp = scores[j];
                scores[j] = scores[j + 1];
                scores[j + 1] = temp;
                int tempIndex = indices[j];
                indices[j] = indices[j + 1];
                indices[j + 1] = tempIndex;
            }
        }
    }
    // 順位を計算して出力
    int rank = 1;
    for (int i = 0; i < N; i++) {
        if (i > 0 && scores[i] != scores[i - 1]) {
            rank = i + 1;
        }
        printf("%d %d %d
", rank, scores[i], indices[i]);
    }
    return 0;
}

