import java.util.*;

public class LogAnalyzer {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = Integer.parseInt(scanner.nextLine());
        Map<String, Integer> userActionCount = new HashMap<>();
        for (int i = 0; i < N; i++) {
            String logEntry = scanner.nextLine();
            String[] parts = logEntry.split(" ");
            String userId = parts[1];
            userActionCount.put(userId, userActionCount.getOrDefault(userId, 0) + 1);
        }
        String targetUserId = scanner.nextLine();
        System.out.println(targetUserId + ": " + userActionCount.getOrDefault(targetUserId, 0));
    }
}

#include <stdio.h>
#include <string.h>
#include <stdlib.h>
int cmp(const void *a, const void *b) {
    int len_a = strlen(*(const char **)a);
    int len_b = strlen(*(const char **)b);
    if (len_a != len_b) return len_b - len_a;
    return strcmp(*(const char **)a, *(const char **)b);
}
