import java.util.*;

public class ChatFilter {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = Integer.parseInt(scanner.nextLine());
        Set<String> forbiddenWords = new HashSet<>();
        for (int i = 0; i < N; i++) {
            forbiddenWords.add(scanner.nextLine().trim());
        }
        String message = scanner.nextLine();
        String replacement = scanner.nextLine();

        for (String word : forbiddenWords) {
            message = message.replaceAll("\b" + word + "\b", replacement);
        }

        String[] words = message.split("\s+");
        Arrays.sort(words, (a, b) -> {
            if (b.length() != a.length()) {
                return Integer.compare(b.length(), a.length());
            } else {
                return a.compareTo(b);
            }
        });

        System.out.println(String.join(" ", words));
    }
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 100
typedef struct Node {
    char name[50];
    struct Node* next;
} Node;
Node* graph[MAX];
int visited[MAX];
char order[MAX][50];
int orderIndex = 0;
void dfs(int index) {
    visited[index] = 1;
    strcpy(order[orderIndex++], graph[index]->name);
    Node* temp = graph[index]->next;
    while (temp != NULL) {
        int nextIndex = -1;
        for (int i = 0; i < MAX; i++) {
            if (graph[i] != NULL && strcmp(graph[i]->name, temp->name) == 0) {
                nextIndex = i;
                break;
            }
        }
        if (nextIndex != -1 && !visited[nextIndex]) {
            dfs(nextIndex);
        }
        temp = temp->next;
    }
}
int main() {
    int N;
    scanf("%d", &N);
    char A[50], B[50];
    for (int i = 0; i < MAX; i++) {
        graph[i] = NULL;
        visited[i] = 0;
    }
    for (int i = 0; i < N; i++) {
        scanf("%s %s", A, B);
        int indexA = -1, indexB = -1;
        for (int j = 0; j < MAX; j++) {
            if (graph[j] != NULL && strcmp(graph[j]->name, A) == 0) {
                indexA = j;
            }
            if (graph[j] != NULL && strcmp(graph[j]->name, B) == 0) {
                indexB = j;
            }
        }
        if (indexA == -1) {
            indexA = i;
            graph[indexA] = (Node*)malloc(sizeof(Node));
            strcpy(graph[indexA]->name, A);
            graph[indexA]->next = NULL;
        }
        if (indexB == -1) {
            indexB = i;
            graph[indexB] = (Node*)malloc(sizeof(Node));
            strcpy(graph[indexB]->name, B);
            graph[indexB]->next = NULL;
        }
        Node* newNode = (Node*)malloc(sizeof(Node));
        strcpy(newNode->name, B);
        newNode->next = graph[indexA]->next;
        graph[indexA]->next = newNode;
    }
    for (int i = 0; i < MAX; i++) {
        if (graph[i] != NULL && !visited[i]) {
            dfs(i);
        }
    }
    for (int i = 0; i < orderIndex; i++) {
        printf("%s ", order[i]);
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <unordered_map>
#include <unordered_set>
#include <stack>
#include <string>
using namespace std;
int main() {
    int N;
    cin >> N;
    unordered_map<string, vector<string>> graph;
    for (int i = 0; i < N; ++i) {
        string A, B;
        cin >> A >> B;
        graph[A].push_back(B);
    }
    unordered_set<string> visited;
    stack<string> s;
    string start;
    // Find a starting package (the first key in the graph)
    if (!graph.empty()) {
        start = graph.begin()->first;
        s.push(start);
    }
    vector<string> result;
    while (!s.empty()) {
        string current = s.top();
        s.pop();
        if (visited.find(current) == visited.end()) {
            visited.insert(current);
            result.push_back(current);
            for (const string& neighbor : graph[current]) {
                if (visited.find(neighbor) == visited.end()) {
                    s.push(neighbor);
                }
            }
        }
    }
    for (const string& pkg : result) {
        cout << pkg << " ";
    }
    cout << endl;
    return 0;
}

import java.util.*;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        scanner.nextLine();
        Map<String, List<String>> graph = new HashMap<>();
        Set<String> visited = new HashSet<>();
        StringBuilder result = new StringBuilder();
        for (int i = 0; i < N; i++) {
            String[] line = scanner.nextLine().split(" ");
            graph.computeIfAbsent(line[0], k -> new ArrayList<>()).add(line[1]);
        }
        for (String packageName : graph.keySet()) {
            if (!visited.contains(packageName)) {
                dfs(packageName, graph, visited, result);
            }
        }
        System.out.println(result.toString().trim());
    }
    private static void dfs(String packageName, Map<String, List<String>> graph, Set<String> visited, StringBuilder result) {
        visited.add(packageName);
        result.append(packageName).append(" ");
        if (graph.containsKey(packageName)) {
            for (String dependency : graph.get(packageName)) {
                if (!visited.contains(dependency)) {
                    dfs(dependency, graph, visited, result);
                }
            }
        }
    }
}

