            lcm = lcm(lcm, numbers.get(i));
        }
        System.out.println(lcm);
    }
    public static int gcd(int a, int b) {
        while (b != 0) {
            int temp = b;
            b = a % b;
            a = temp;
        }
        return a;
    }
    public static int lcm(int a, int b) {
        return a * (b / gcd(a, b));
    }
}

