        visitors.sort((a, b) -> {
            if (a[0] != b[0]) {
                return Integer.compare(a[0], b[0]); 
            } else if (a[1] != b[1]) {
                return Integer.compare(b[1], a[1]);
            } else {
                return Integer.compare(a[2], b[2]);
            }
        });
        for (int[] visitor : visitors) {
            System.out.println(visitor[0] + " " + visitor[1]);
        }
    }
}

