import java.util.*;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int M = sc.nextInt();
        List<List<Integer>> graph = new ArrayList<>(N + 1);
        for (int i = 0; i <= N; i++) {
            graph.add(new ArrayList<>());
        }
        for (int i = 0; i < M; i++) {
            int u = sc.nextInt();
            int v = sc.nextInt();
            graph.get(u).add(v);
        }
        int S = sc.nextInt();
        int T = sc.nextInt();
        System.out.println(canReach(S, T, graph) ? "YES" : "NO");
    }

    private static boolean canReach(int S, int T, List<List<Integer>> graph) {
        boolean[] visited = new boolean[graph.size()];
        return dfs(S, T, graph, visited);
    }

    private static boolean dfs(int current, int target, List<List<Integer>> graph, boolean[] visited) {
        if (current == target) return true;
        visited[current] = true;
        for (int neighbor : graph.get(current)) {
            if (!visited[neighbor] && dfs(neighbor, target, graph, visited)) {
                return true;
            }
        }
        return false;
    }
}

