#include <stdio.h>
#include <string.h>
#include <stdlib.h>
#define MAX_OPERATIONS 100
typedef struct {
    char key[50];
    char value[50];
} Operation;
int main() {
    int N;
    scanf("%d", &N);
    Operation operations[MAX_OPERATIONS];
    int operationCount = 0;
    char command[10], key[50], value[50];
    for (int i = 0; i < N; i++) {
        scanf("%s", command);
        if (strcmp(command, "add") == 0) {
            scanf("%s %s", key, value);
            strcpy(operations[operationCount].key, key);
            strcpy(operations[operationCount].value, value);
            operationCount++;
        } else if (strcmp(command, "delete") == 0) {
            scanf("%s", key);
            for (int j = 0; j < operationCount; j++) {
                if (strcmp(operations[j].key, key) == 0) {
                    for (int k = j; k < operationCount - 1; k++) {
                        operations[k] = operations[k + 1];
                    }
                    operationCount--;
                    break;
                }
            }
        } else if (strcmp(command, "update") == 0) {
            scanf("%s %s", key, value);
            for (int j = 0; j < operationCount; j++) {
                if (strcmp(operations[j].key, key) == 0) {
                    strcpy(operations[j].value, value);
                    break;
                }
            }
        } else if (strcmp(command, "undo") == 0) {
            if (operationCount > 0) {
                operationCount--;
            }
        }
    }
    printf("{");
    for (int i = 0; i < operationCount; i++) {
        printf("'%s': '%s'", operations[i].key, operations[i].value);
        if (i < operationCount - 1) {
            printf(", ");
        }
    }
    printf("}
");
    return 0;
}

