#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>
#define MAX 100
int queue[MAX*MAX][2];
int front = 0, rear = 0;
void enqueue(int x, int y) {
    queue[rear][0] = x;
    queue[rear][1] = y;
    rear++;
}
int dequeue(int *x, int *y) {
    if (front < rear) {
        *x = queue[front][0];
        *y = queue[front][1];
        front++;
        return 1;
    }
    return 0;
}
int bfs(int grid[MAX][MAX], int n, int m, int sx, int sy, int tx, int ty) {
    int directions[4][2] = {{1, 0}, {-1, 0}, {0, 1}, {0, -1}};
    bool visited[MAX][MAX];
    memset(visited, false, sizeof(visited));
    enqueue(sx, sy);
    visited[sx][sy] = true;
    int distance[MAX][MAX];
    memset(distance, -1, sizeof(distance));
    distance[sx][sy] = 0;
    while (front < rear) {
        int x, y;
        dequeue(&x, &y);
        for (int i = 0; i < 4; i++) {
            int newX = x + directions[i][0];
            int newY = y + directions[i][1];
            if (newX >= 0 && newX < n && newY >= 0 && newY < m && 
                grid[newX][newY] == 0 && !visited[newX][newY]) {
                visited[newX][newY] = true;
                distance[newX][newY] = distance[x][y] + 1;
                enqueue(newX, newY);
                if (newX == tx && newY == ty) {
                    return distance[newX][newY];
                }
            }
        }
    }
    return -1;
}
int main() {
    int n, m;
    scanf("%d %d", &n, &m);
    int grid[MAX][MAX];
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            scanf("%d", &grid[i][j]);
        }
    }
    int sx, sy, tx, ty;
    scanf("%d %d", &sx, &sy);
    scanf("%d %d", &tx, &ty);
    int result = bfs(grid, n, m, sx, sy, tx, ty);
    printf("%d
", result);
    return 0;
}

