#include <stdio.h>
#include <string.h>
struct Patient {
    char name[21];
    int priority;
};
int main() {
    int n;
    scanf("%d", &n);
    struct Patient patients[100];
    for (int i = 0; i < n; i++) {
        scanf("%s %d", patients[i].name, &patients[i].priority);
    }
    for (int i = 0; i < n; i++) {
        int maxIndex = -1;
        for (int j = 0; j < n; j++) {
            if (patients[j].priority > 0 && (maxIndex == -1 || patients[j].priority > patients[maxIndex].priority)) {
                maxIndex = j;
            }
        }
        if (maxIndex == -1) break;
        printf("%s %d
", patients[maxIndex].name, patients[maxIndex].priority);
        patients[maxIndex].priority = 0; // 診察後削除
        for (int j = 0; j < n; j++) {
            if (patients[j].priority > 0) {
                patients[j].priority--;
            }
        }
    }
    int remaining = 0;
    for (int i = 0; i < n; i++) {
        if (patients[i].priority > 0) {
            remaining = 1;
            break;
        }
    }
    if (!remaining) {
        printf("全ての患者が診察されました
");
    }
