#include <iostream>
#include <vector>
#include <algorithm>
struct Patient {
    std::string name;
    int priority;
};
int main() {
    int n;
    std::cin >> n;
    std::vector<Patient> patients(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> patients[i].name >> patients[i].priority;
    }
    for (int i = 0; i < n; ++i) {
        // Sort patients by priority in descending order
        std::sort(patients.begin(), patients.end(), [](const Patient &a, const Patient &b) {
            return a.priority > b.priority;
        });
        // Treat the patient with the highest priority
        if (patients.empty()) break;
        patients[0].priority--;
        if (patients[0].priority == 0) {
            patients.erase(patients.begin());
        }
    }
    if (patients.empty()) {
        std::cout << "全ての患者が診察されました" << std::endl;
    } else {
        for (const auto &patient : patients) {
            std::cout << patient.name << " " << patient.priority << std::endl;
        }
    }
    return 0;
}

import java.util.*;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        scanner.nextLine();
        List<Pair> patients = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            String name = scanner.next();
            int priority = scanner.nextInt();
            patients.add(new Pair(name, priority));
        }
        while (!patients.isEmpty()) {
            patients.sort((a, b) -> b.priority - a.priority);
            Pair current = patients.remove(0);
            current.priority--;
            if (current.priority > 0) {
                patients.add(current);
            }
        }
        if (patients.isEmpty()) {
            System.out.println("全ての患者が診察されました");
        } else {
            patients.sort((a, b) -> b.priority - a.priority);
            for (Pair patient : patients) {
                System.out.println(patient.name + " " + patient.priority);
            }
        }
    }
    static class Pair {
        String name;
        int priority;
        Pair(String name, int priority) {
            this.name = name;
            this.priority = priority;
        }
    }
}

