from typing import List, Tuple

def grade_evaluation(score: int) -> Tuple[str, bool]:
    if score < 0 or score > 100:
        raise ValueError('Score must be between 0 and 100')
    if score >= 90:
        return ('A', True)
    elif score >= 80:
        return ('B', True)
    elif score >= 70:
        return ('C', True)
    elif score >= 60:
        return ('D', True)
    else:
        return ('F', False)

def process_student_scores(scores: List[Tuple[int, bool]]) -> List[Tuple[str, bool]]:
    results = []
    for score, absent in scores:
        if absent:
            results.append(('F', False))
        else:
            results.append(grade_evaluation(score))
    return results

#include <stdio.h>
#include <stdbool.h>
#include <stdlib.h>
#include <string.h>
typedef struct {
    char grade;
    bool passed;
} GradeResult;
GradeResult grade_evaluation(int score) {
    GradeResult result;
    if (score < 0 || score > 100) {
        result.grade = 'F';
        result.passed = false;
    } else if (score >= 90) {
        result.grade = 'A';
        result.passed = true;
    } else if (score >= 80) {
        result.grade = 'B';
        result.passed = true;
    } else if (score >= 70) {
        result.grade = 'C';
        result.passed = true;
    } else if (score >= 60) {
        result.grade = 'D';
        result.passed = true;
    } else {
        result.grade = 'F';
        result.passed = false;
    }
    return result;
}
GradeResult* process_student_scores(int scores[][2], int count) {
    GradeResult* results = (GradeResult*)malloc(count * sizeof(GradeResult));
    for (int i = 0; i < count; i++) {
        if (scores[i][1]) { // absent
            results[i] = (GradeResult) {'F', false};
        } else {
            results[i] = grade_evaluation(scores[i][0]);
        }
    }
    return results;
}
int main() {
    int student_scores[4][2] = {{85, 0}, {45, 1}, {70, 0}, {55, 0}};
    int count = 4;
    GradeResult* results = process_student_scores(student_scores, count);
    for (int i = 0; i < count; i++) {
        printf("('%%c', %%s)
", results[i].grade, results[i].passed ? "true" : "false");
    }
    free(results);
    return 0;
}

#include <iostream>
