using namespace std;
tuple<string, bool> grade_evaluation(int score) {
    if (score < 60) return make_tuple("F", false);
    else if (score < 70) return make_tuple("D", true);
    else if (score < 80) return make_tuple("C", true);
    else if (score < 90) return make_tuple("B", true);
    else return make_tuple("A", true);
}
vector<tuple<string, bool>> process_student_scores(vector<tuple<int, bool>> scores) {
    vector<tuple<string, bool>> results;
    for (const auto& score : scores) {
        int numeric_score = get<0>(score);
        bool absent = get<1>(score);
        if (absent) {
            results.push_back(make_tuple("F", false));
        } else {
            results.push_back(grade_evaluation(numeric_score));
        }
    }
    return results;
}
int main() {
    vector<tuple<int, bool>> scores = {{85, false}, {45, true}, {70, false}, {55, false}};
    vector<tuple<string, bool>> results = process_student_scores(scores);
    for (const auto& result : results) {
        cout << "(" << get<0>(result) << ", " << (get<1>(result) ? "true" : "false") << ") ";
    }
    return 0;
}

import java.util.ArrayList;
import java.util.List;
import java.util.Arrays;
public class StudentGrades {
    public static void main(String[] args) {
        List<Tuple> scores = Arrays.asList(
            new Tuple(85, false),
            new Tuple(45, true),
            new Tuple(70, false),
            new Tuple(55, false)
        );
        List<Tuple> results = processStudentScores(scores);
        System.out.println(results);
    }
    public static List<Tuple> processStudentScores(List<Tuple> scores) {
        List<Tuple> results = new ArrayList<>();
        for (Tuple score : scores) {
            results.add(gradeEvaluation(score.score, score.absent));
        }
        return results;
    }
    public static Tuple gradeEvaluation(int score, boolean absent) {
        if (absent) {
            return new Tuple("F", false);
        } else if (score >= 90) {
            return new Tuple("A", true);
        } else if (score >= 80) {
            return new Tuple("B", true);
        } else if (score >= 70) {
            return new Tuple("C", true);
        } else if (score >= 60) {
            return new Tuple("D", true);
        } else {
            return new Tuple("F", false);
        }
    }
    static class Tuple {
        int score;
        boolean absent;
        Tuple(String grade, boolean pass) {
            this.grade = grade;
            this.pass = pass;
        }
    }
}
